import{_ as s,o as n,c as t,a1 as e}from"./chunks/framework.CMt7O7Ol.js";const b=JSON.parse('{"title":"第四章：止损、风险与仓位设计","description":"","frontmatter":{},"headers":[],"relativePath":"trading/intraday-entry/04-risk-stop-and-position-sizing.md","filePath":"trading/intraday-entry/04-risk-stop-and-position-sizing.md"}'),p={name:"trading/intraday-entry/04-risk-stop-and-position-sizing.md"};function l(i,a,d,o,c,r){return n(),t("div",null,[...a[0]||(a[0]=[e(`<h1 id="第四章-止损、风险与仓位设计" tabindex="-1">第四章：止损、风险与仓位设计 <a class="header-anchor" href="#第四章-止损、风险与仓位设计" aria-label="Permalink to &quot;第四章：止损、风险与仓位设计&quot;">​</a></h1><blockquote><p>止损不是“我最多愿意亏多少钱”，而是市场在什么位置证明交易逻辑已经失效；仓位则负责把这个失效距离换算成可承受的金额。</p></blockquote><h2 id="一、先决定哪里错-再决定买多少" tabindex="-1">一、先决定哪里错，再决定买多少 <a class="header-anchor" href="#一、先决定哪里错-再决定买多少" aria-label="Permalink to &quot;一、先决定哪里错，再决定买多少&quot;">​</a></h2><p>科学的下单顺序是：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>确定交易逻辑</span></span>
<span class="line"><span>→ 标记结构失效点</span></span>
<span class="line"><span>→ 计算入场到失效点的距离</span></span>
<span class="line"><span>→ 设定单笔风险金额</span></span>
<span class="line"><span>→ 倒推出允许仓位</span></span>
<span class="line"><span>→ 检查第一目标与盈亏比</span></span>
<span class="line"><span>→ 最后才下单</span></span></code></pre></div><p>错误顺序通常是：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>先买一个习惯仓位</span></span>
<span class="line"><span>→ 发现波动太大</span></span>
<span class="line"><span>→ 为了少亏而随意收紧止损</span></span>
<span class="line"><span>→ 被正常波动扫出</span></span>
<span class="line"><span>→ 价格随后按原方向运行</span></span></code></pre></div><p>因此，<strong>止损距离决定仓位，仓位不能反过来决定止损位置</strong>。</p><h2 id="二、用-r-统一衡量风险" tabindex="-1">二、用 R 统一衡量风险 <a class="header-anchor" href="#二、用-r-统一衡量风险" aria-label="Permalink to &quot;二、用 R 统一衡量风险&quot;">​</a></h2><p>把每笔交易计划承担的最大亏损定义为 <code>1R</code>。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1R = 账户权益 × 单笔风险比例</span></span></code></pre></div><p>假设账户权益为 50,000 美元：</p><table tabindex="0"><thead><tr><th>单笔风险比例</th><th style="text-align:right;">1R</th></tr></thead><tbody><tr><td>0.25%</td><td style="text-align:right;">$125</td></tr><tr><td>0.40%</td><td style="text-align:right;">$200</td></tr><tr><td>0.50%</td><td style="text-align:right;">$250</td></tr><tr><td>1.00%</td><td style="text-align:right;">$500</td></tr></tbody></table><p>风险比例不是越高越好。它只决定连续错误时账户回撤的速度，并不会提高策略本身的胜率。</p><h3 id="学习阶段的示范参数" tabindex="-1">学习阶段的示范参数 <a class="header-anchor" href="#学习阶段的示范参数" aria-label="Permalink to &quot;学习阶段的示范参数&quot;">​</a></h3><p>下面是一套用于训练的保守模板，不是适合所有账户的固定标准：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>单笔风险：0.25%—0.50%</span></span>
<span class="line"><span>单日硬上限：2R</span></span>
<span class="line"><span>连续两笔完整止损：当天停止主动交易</span></span>
<span class="line"><span>周度回撤达到 4R：下一周风险减半并复盘</span></span></code></pre></div><p>只有在同一套 setup 积累足够样本、执行偏差稳定后，才讨论提高风险。不能因为连续盈利几次就临时放大仓位。</p><h2 id="三、四种失效-价格、结构、时间与环境" tabindex="-1">三、四种失效：价格、结构、时间与环境 <a class="header-anchor" href="#三、四种失效-价格、结构、时间与环境" aria-label="Permalink to &quot;三、四种失效：价格、结构、时间与环境&quot;">​</a></h2><h3 id="_1-价格失效" tabindex="-1">1. 价格失效 <a class="header-anchor" href="#_1-价格失效" aria-label="Permalink to &quot;1. 价格失效&quot;">​</a></h3><p>价格越过一个明确数值，交易逻辑不再成立。</p><p>例如：</p><ul><li>向上假突破做空，价格重新站上假突破高点。</li><li>跌破回抽做空，价格重新站回原支撑并完成回踩。</li><li>下方海龟汤做多，价格重新跌破扫荡低点。</li></ul><p>价格失效最容易量化，但不能脱离 K 线收盘和市场波动机械执行。</p><h3 id="_2-结构失效" tabindex="-1">2. 结构失效 <a class="header-anchor" href="#_2-结构失效" aria-label="Permalink to &quot;2. 结构失效&quot;">​</a></h3><p>价格行为已经破坏建仓依据，即使尚未触及最远止损，也应退出。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>多头：更高低点被破坏，旧区间被重新接受</span></span>
<span class="line"><span>空头：更低高点被突破，原阻力被重新收回</span></span>
<span class="line"><span>失败突破：市场重新接受在突破方向</span></span>
<span class="line"><span>节点反转：节点被连续实体穿越，不再产生拒绝</span></span></code></pre></div><p>结构失效通常比“等到最大亏损”更早，因此它是主动退出依据；预设的最大止损则是执行失败或快速行情下的最后保护。</p><h3 id="_3-时间失效" tabindex="-1">3. 时间失效 <a class="header-anchor" href="#_3-时间失效" aria-label="Permalink to &quot;3. 时间失效&quot;">​</a></h3><p>日内 setup 依赖价格在有限时间内离开建仓区。如果入场后持续停留在关键位附近，说明预期中的主动买卖力量没有出现。</p><p>训练时可以采用：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1 分钟执行：入场后 2—4 根 K 仍无位移 → 减仓或退出</span></span>
<span class="line"><span>3 分钟执行：入场后 2—3 根 K 仍无位移 → 重新评估</span></span>
<span class="line"><span>0DTE：越接近到期，时间止损越不能放松</span></span></code></pre></div><p>时间止损不是固定闹钟。强趋势可以较快确认；震荡环境中，迟迟不动本身就是 setup 质量下降的证据。</p><h3 id="_4-环境失效" tabindex="-1">4. 环境失效 <a class="header-anchor" href="#_4-环境失效" aria-label="Permalink to &quot;4. 环境失效&quot;">​</a></h3><p>交易方向可能没有立即错误，但支撑它的环境已经改变：</p><ul><li>关键节点或 GEX 结构快速迁移。</li><li>价格反复穿越 VWAP，原趋势退化为震荡。</li><li>SPX 与 ES/NQ 明显不同步。</li><li>期权流与价格没有后续确认。</li><li>数据源异常、延迟或相互冲突。</li><li>重大事件即将公布，原波动假设失效。</li></ul><p>环境失效时优先降仓、缩短目标或退出，而不是继续增加指标为持仓辩护。</p><h2 id="四、结构止损应该放在哪里" tabindex="-1">四、结构止损应该放在哪里 <a class="header-anchor" href="#四、结构止损应该放在哪里" aria-label="Permalink to &quot;四、结构止损应该放在哪里&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Setup</th><th>建议失效位置</th><th>不合理做法</th></tr></thead><tbody><tr><td>突破回踩做多</td><td>回踩低点下方，或重新进入旧区间的位置</td><td>紧贴突破线随意放一个固定点数</td></tr><tr><td>跌破回抽做空</td><td>反抽高点上方，或重新站回旧区间的位置</td><td>因期权价格波动就不断移动止损</td></tr><tr><td>上方海龟汤做空</td><td>扫荡高点外，或重新站稳区间上沿</td><td>看见第一根阴线后把止损放在阴线高点内</td></tr><tr><td>下方海龟汤做多</td><td>扫荡低点外，或重新跌回区间下沿</td><td>仅按账户亏损金额确定价格位置</td></tr><tr><td>区间边缘反转</td><td>边界外一格并结合拒绝 K 的极值</td><td>在区间中轴才止损</td></tr></tbody></table><p>止损需要给正常噪音留出空间，但“更宽”不代表“更安全”。止损距离变宽时，仓位必须同步缩小。</p><h2 id="五、仓位计算公式" tabindex="-1">五、仓位计算公式 <a class="header-anchor" href="#五、仓位计算公式" aria-label="Permalink to &quot;五、仓位计算公式&quot;">​</a></h2><h3 id="_1-股票、etf-或按点计价的产品" tabindex="-1">1. 股票、ETF 或按点计价的产品 <a class="header-anchor" href="#_1-股票、etf-或按点计价的产品" aria-label="Permalink to &quot;1. 股票、ETF 或按点计价的产品&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>单位风险 = |入场价 - 止损价| + 预估滑点与费用</span></span>
<span class="line"><span>允许数量 = 向下取整（1R ÷ 单位风险）</span></span></code></pre></div><h3 id="构造例-股票突破回踩" tabindex="-1">构造例：股票突破回踩 <a class="header-anchor" href="#构造例-股票突破回踩" aria-label="Permalink to &quot;构造例：股票突破回踩&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>账户权益：$40,000</span></span>
<span class="line"><span>单笔风险：0.25% = $100</span></span>
<span class="line"><span>计划入场：$52.00</span></span>
<span class="line"><span>结构止损：$51.50</span></span>
<span class="line"><span>预估滑点与费用：$0.05 / 股</span></span>
<span class="line"><span></span></span>
<span class="line"><span>单位风险 = 52.00 - 51.50 + 0.05 = $0.55</span></span>
<span class="line"><span>允许数量 = floor(100 ÷ 0.55) = 181 股</span></span></code></pre></div><p>实际执行可进一步向下取整为 175 或 180 股，不能为了凑整数向上超过风险预算。</p><h3 id="_2-期货或差价合约" tabindex="-1">2. 期货或差价合约 <a class="header-anchor" href="#_2-期货或差价合约" aria-label="Permalink to &quot;2. 期货或差价合约&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>单位风险 = 止损点数 × 每点价值 + 滑点与费用</span></span>
<span class="line"><span>允许合约数 = 向下取整（1R ÷ 单位风险）</span></span></code></pre></div><p>每个产品的点值和最小变动单位不同，必须使用交易所或券商的合约规格，不能凭股票仓位经验换算。</p><h3 id="_3-买入期权" tabindex="-1">3. 买入期权 <a class="header-anchor" href="#_3-买入期权" aria-label="Permalink to &quot;3. 买入期权&quot;">​</a></h3><p>买入 call 或 put 时，到期最大亏损通常是支付的全部权利金；期权教育委员会也将买入 call 的最大亏损定义为初始权利金。[<a href="https://www.optionseducation.org/strategies/all-strategies/long-call" target="_blank" rel="noreferrer">OIC：Long Call</a>]</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>绝对最大亏损 = 权利金 × 合约乘数 × 合约数</span></span>
<span class="line"><span>计划止损风险 ≈ |入场权利金 - 计划退出权利金| × 合约乘数</span></span></code></pre></div><p>计划止损风险只能用于正常成交情形。快速波动、价差扩大或系统延迟可能使实际退出价差于计划，因此还要检查“全部权利金损失”是否会对账户造成不可接受的伤害。</p><p>SPX 期权的合约乘数为 100 美元，即权利金每变动 1.00，对单张合约价值影响 100 美元；SPX 采用现金结算和欧式行权。[<a href="https://www.cboe.com/tradable-products/sp-500/spx-options/" target="_blank" rel="noreferrer">Cboe：SPX Options</a>]</p><h3 id="构造例-最小合约仍然太大" tabindex="-1">构造例：最小合约仍然太大 <a class="header-anchor" href="#构造例-最小合约仍然太大" aria-label="Permalink to &quot;构造例：最小合约仍然太大&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1R：$200</span></span>
<span class="line"><span>一张 SPX 0DTE call 权利金：$3.20</span></span>
<span class="line"><span>购买成本：$320</span></span>
<span class="line"><span>计划止损：期权价格跌到 $2.20</span></span>
<span class="line"><span>正常计划风险：约 $100 + 滑点</span></span>
<span class="line"><span>极端最大风险：$320</span></span></code></pre></div><p>虽然正常止损看似符合 1R，但一张合约的极端最大风险已经达到 1.6R。如果账户无法接受这种跳空或执行风险，正确动作不是放宽预算，而是：</p><ol><li>换用更小的产品；</li><li>使用有限风险价差；</li><li>等权利金下降且结构仍有效；</li><li>放弃这笔交易。</li></ol><p><strong>最小可交易单位超过风险预算时，不交易本身就是仓位管理。</strong></p><h3 id="_4-debit-spread-等有限风险结构" tabindex="-1">4. Debit Spread 等有限风险结构 <a class="header-anchor" href="#_4-debit-spread-等有限风险结构" aria-label="Permalink to &quot;4. Debit Spread 等有限风险结构&quot;">​</a></h3><p>以牛市 call 价差为例，其到期最大亏损是建立组合支付的净权利金；最大盈利为执行价宽度减去净权利金。[<a href="https://www.optionseducation.org/strategies/all-strategies/bull-call-spread-debit-call-spread" target="_blank" rel="noreferrer">OIC：Bull Call Spread</a>]</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>净支出：$2.00</span></span>
<span class="line"><span>合约乘数：100</span></span>
<span class="line"><span>单组最大亏损：$200</span></span></code></pre></div><p>如果 <code>1R = $200</code>，一组价差正好占用完整风险预算。但盘中仍应依据 SPX 结构失效主动退出，而不是因为“最大亏损有限”就持有到归零。</p><p>有限风险结构一旦建立，不能临时拆掉保护腿，把有限风险变成裸露风险。如果市场观点发生变化，应整体平仓，再重新建立新的独立交易。</p><h2 id="六、分批建仓-证据增加-风险不能增加" tabindex="-1">六、分批建仓：证据增加，风险不能增加 <a class="header-anchor" href="#六、分批建仓-证据增加-风险不能增加" aria-label="Permalink to &quot;六、分批建仓：证据增加，风险不能增加&quot;">​</a></h2><p>分批建仓的正确逻辑是：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>候选位置出现 → 小仓试探</span></span>
<span class="line"><span>触发得到确认 → 增加主要仓位</span></span>
<span class="line"><span>价格再次延续 → 只在新止损可以上移时考虑增加</span></span>
<span class="line"><span>任何时刻的总计划亏损 ≤ 原定 1R</span></span></code></pre></div><h3 id="三段式示范" tabindex="-1">三段式示范 <a class="header-anchor" href="#三段式示范" aria-label="Permalink to &quot;三段式示范&quot;">​</a></h3><table tabindex="0"><thead><tr><th>阶段</th><th>证据</th><th style="text-align:right;">仓位参考</th><th>风险要求</th></tr></thead><tbody><tr><td>观察仓</td><td>关键位置 + 初始触发</td><td style="text-align:right;">1/4</td><td>失效点必须明确</td></tr><tr><td>主仓</td><td>回踩守住 + 再次启动</td><td style="text-align:right;">增至 3/4</td><td>重新计算总风险，不得超过 1R</td></tr><tr><td>延续仓</td><td>新结构形成且原仓止损可上移</td><td style="text-align:right;">最多满仓</td><td>不能在远离关键位时追价</td></tr></tbody></table><p>这不是要求每笔交易都分三次。强趋势可能只给一次合理回踩；震荡环境则可能根本不值得建立主仓。</p><h3 id="不能这样加仓" tabindex="-1">不能这样加仓 <a class="header-anchor" href="#不能这样加仓" aria-label="Permalink to &quot;不能这样加仓&quot;">​</a></h3><ul><li>亏损后为了降低平均成本而加仓。</li><li>价格已经远离失效点，因为害怕错过而追仓。</li><li>新增仓位后，总风险超过原定 1R。</li><li>仅因期权流出现一笔大单就放大仓位。</li><li>组合已经是有限风险结构，却拆腿追求更高收益。</li></ul><h2 id="七、仓位应随环境折扣" tabindex="-1">七、仓位应随环境折扣 <a class="header-anchor" href="#七、仓位应随环境折扣" aria-label="Permalink to &quot;七、仓位应随环境折扣&quot;">​</a></h2><p>基础仓位计算完成后，还要根据证据质量应用折扣：</p><table tabindex="0"><thead><tr><th>环境</th><th style="text-align:right;">建议风险系数</th><th>原因</th></tr></thead><tbody><tr><td>关键位 + 回踩确认 + 指数同步</td><td style="text-align:right;">1.0</td><td>主证据完整</td></tr><tr><td>价格确认，但 ES/NQ 不同步</td><td style="text-align:right;">0.5—0.75</td><td>跨市场证据冲突</td></tr><tr><td>开盘前半小时，GEX/flow 尚不稳定</td><td style="text-align:right;">0—0.5</td><td>容易出现假信号</td></tr><tr><td>价格在两个节点中间</td><td style="text-align:right;">0</td><td>无结构优势</td></tr><tr><td>数据源异常或事件即将公布</td><td style="text-align:right;">0</td><td>风险无法可靠估计</td></tr><tr><td>当日已亏 1R</td><td style="text-align:right;">下一笔减半或停止</td><td>防止情绪和环境共同恶化</td></tr></tbody></table><p>这里的系数是训练模板。真正的折扣应由自己的交易日志验证，而不是永久照抄。</p><h2 id="八、0dte-的特殊风险" tabindex="-1">八、0DTE 的特殊风险 <a class="header-anchor" href="#八、0dte-的特殊风险" aria-label="Permalink to &quot;八、0DTE 的特殊风险&quot;">​</a></h2><p>0DTE 不只是“更便宜的方向工具”。临近到期时，Delta、Gamma、Theta 与隐含波动率变化会使权利金对价格和时间极为敏感。</p><p>实盘需要额外遵守：</p><ol><li>止损首先绑定 SPX 结构，同时设置期权端的灾难保护。</li><li>不把全部权利金都视为默认可亏金额。</li><li>接近目标节点先兑现一部分，不等“刚好打满目标”。</li><li>快速盈利后，可用新的结构低点或权利金高点回撤管理剩余仓位，但追踪止盈不能替代初始止损。</li><li>流动性下降、买卖价差扩大或事件临近时，仓位必须折扣。</li><li>不因“最大亏损有限”而把多个有限风险组合叠加成过大的账户风险。</li></ol><p>FINRA 的日内交易风险披露强调，日内交易可能产生快速而重大的亏损，波动或市场异常时也可能难以及时以合理价格退出。[<a href="https://www.finra.org/rules-guidance/rulebooks/finra-rules/2270" target="_blank" rel="noreferrer">FINRA Rule 2270</a>]</p><h2 id="九、每日风险熔断" tabindex="-1">九、每日风险熔断 <a class="header-anchor" href="#九、每日风险熔断" aria-label="Permalink to &quot;九、每日风险熔断&quot;">​</a></h2><p>风险熔断的作用不是预测下一笔会不会赢，而是在执行质量下降时保护账户。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>达到 -1R：暂停，复核两笔交易是否属于同一错误</span></span>
<span class="line"><span>达到 -2R：当天停止主动交易</span></span>
<span class="line"><span>连续两笔完整止损：停止寻找“翻本单”</span></span>
<span class="line"><span>出现数据故障或异常滑点：降级为观察模式</span></span>
<span class="line"><span>违反一次预设规则：下一笔风险至少减半</span></span></code></pre></div><p>“今天必须赚回来”不是交易目标。每日风险预算一旦用完，继续交易相当于在没有计划的情况下重新提高风险上限。</p><h2 id="十、盈亏比必须基于结构-而不是愿望" tabindex="-1">十、盈亏比必须基于结构，而不是愿望 <a class="header-anchor" href="#十、盈亏比必须基于结构-而不是愿望" aria-label="Permalink to &quot;十、盈亏比必须基于结构，而不是愿望&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>计划盈亏比 = 第一合理目标距离 ÷ 结构止损距离</span></span></code></pre></div><p>例如：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>入场：100</span></span>
<span class="line"><span>结构止损：99</span></span>
<span class="line"><span>第一目标：102</span></span>
<span class="line"><span>计划盈亏比 = 2 ÷ 1 = 2R</span></span></code></pre></div><p>如果下一个关键节点只提供 0.7R 的空间，即使方向判断正确，也不一定值得建仓。不能为了得到漂亮的 2R，把目标越过真实阻力随意画远。</p><p>分批止盈后，应记录实际实现的 R，而不是只记录最高浮盈：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>一半仓位在 +1R 退出</span></span>
<span class="line"><span>一半仓位在 +2R 退出</span></span>
<span class="line"><span>实际结果 = 0.5 × 1R + 0.5 × 2R = +1.5R</span></span></code></pre></div><h2 id="十一、下单前风险卡" tabindex="-1">十一、下单前风险卡 <a class="header-anchor" href="#十一、下单前风险卡" aria-label="Permalink to &quot;十一、下单前风险卡&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>账户权益：</span></span>
<span class="line"><span>本笔 1R：</span></span>
<span class="line"><span>交易 Setup：</span></span>
<span class="line"><span>计划入场：</span></span>
<span class="line"><span>结构失效点：</span></span>
<span class="line"><span>时间失效：</span></span>
<span class="line"><span>环境失效：</span></span>
<span class="line"><span>第一目标：</span></span>
<span class="line"><span>计划盈亏比：</span></span>
<span class="line"><span>单位风险：</span></span>
<span class="line"><span>允许数量：</span></span>
<span class="line"><span>分批方案：</span></span>
<span class="line"><span>最坏情形最大亏损：</span></span>
<span class="line"><span>今天已实现 R：</span></span>
<span class="line"><span>今天剩余风险预算：</span></span></code></pre></div><h2 id="十二、本章总结" tabindex="-1">十二、本章总结 <a class="header-anchor" href="#十二、本章总结" aria-label="Permalink to &quot;十二、本章总结&quot;">​</a></h2><p>止损与仓位设计可以浓缩成五句话：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>止损放在逻辑失效处，不放在心理舒服处。</span></span>
<span class="line"><span>先确定失效距离，再倒推允许仓位。</span></span>
<span class="line"><span>分批建仓可以增加证据，但不能突破原定 1R。</span></span>
<span class="line"><span>最小合约超过预算时，换工具或不交易。</span></span>
<span class="line"><span>达到每日熔断后停止，不用下一笔交易修复情绪。</span></span></code></pre></div><p>最终流程是：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>位置与触发</span></span>
<span class="line"><span>→ 定义结构失效</span></span>
<span class="line"><span>→ 计算 1R</span></span>
<span class="line"><span>→ 倒推仓位</span></span>
<span class="line"><span>→ 检查目标与盈亏比</span></span>
<span class="line"><span>→ 执行并按结构管理</span></span>
<span class="line"><span>→ 时间或环境失效时主动退出</span></span></code></pre></div><blockquote><p>本章用于交易教育和风险流程研究，不构成投资建议。示范比例与金额仅用于说明计算方法，实际参数需结合个人账户、产品规则、流动性和风险承受能力。</p></blockquote>`,100)])])}const u=s(p,[["render",l]]);export{b as __pageData,u as default};
